INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "お！\nあそこに困ってそうな人発見！", 0, "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 1.4, 1, "ヒヨリでっす♪\n元気いっぱいがんばるよ♪", "春咲 ひより", 0, 0, 0, 1001, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "大切な人を\n守れるようになりたい…って", 0, "わ、わたし、\nなに言ってるんだろ\nあはは…", 1.4, 1, "みんなみたいに\nわたしも強くならなきゃ", "草野 優衣", 0, 0, 0, 1002, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "キミに必要な集中力と感性が", 0, "少しは磨かれると思いますよ。", 1.4, 1, "フェンシングを始めてみては？", "士条 怜", 0, 0, 0, 1003, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "今日はなにして遊ぶ？", 0, "みそぎはねぇ、\nかくれんぼやりたい！", 1.5, 1, "ねぇ、にいちゃん！", "穂高 みそぎ", 0, 0, 0, 1004, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "ねぇ…", 0, "私といっしょに…\nいかない？", 1.4, 1, "風宮あかりです", "風宮 あかり", 0, 0, 0, 1006, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "プリンたべたいのー", 0, "食べ物の恨みは怖いのー", 1.5, 1, "出雲宮子なのー", "出雲 宮子", 0, 0, 0, 1007, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "キミもボクの美貌に\n吸い寄せられたんだね。", 0, "いいよ。\n見られることは運命さ…", 1.4, 1, "ボクは虹村雪。", "虹村 雪", 0, 0, 0, 1008, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 0, "人呼んで「疾風の冥姫」!!", 1.4, 1, "フッ…聞いて後悔するがいい！", "柊杏奈", 0, 0, 0, 1009, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 0, "ほんまおおきにやわ～♪", 1.5, 1, "マホマホ王国のプリンセス、\nまほ姫どす", "姫宮 真歩", 0, 0, 0, 1010, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "生き別れたお兄ちゃんを探して\n三千世界！", 0, "ここで会ったが\n100年目～！", 1.4, 1, "衣之咲璃乃です！", "衣之咲 璃乃", 0, 0, 0, 1011, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "ち、超能力って…\n何のことかな～？", 0, "…って、お願い！\n誰にも言わないでおいて～！", 1.4, 1, "私はハツネ、\n結構強いんだよ。\nきらーん☆", "柏崎 初音", 0, 0, 0, 1012, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "一応カリスマ読モJKやってまっす！", 0, "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 1.4, 1, "ちょす！\n美波鈴奈だよ～♪", "美波 鈴奈", 0, 0, 0, 1016, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "東京は遊園地みたいなところさー", 0, "でも、沖縄もとってもいいとこさー", 1.4, 1, "はいたーい。\n喜屋武香織さー。", "喜屋武 香織", 0, 0, 0, 1017, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "先生って呼ばれるのは\nくすぐったいから", 0, "イオちゃんって呼んでね。", 1.4, 1, "支倉伊緒です。", "支倉 伊緒", 0, 0, 0, 1018, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "あ！/\お兄ちゃ～ん\nまってよ～", 0, "ミミをおいてかないでぇ～", 1.5, 1, "ふえ…？\nミミ、むずかしいこと\nよくわかんない…", "茜 ミミ", 0, 0, 0, 1020, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "あの……\nふぇ……", 0, "ふぇぇぇぇぇん……", 1.5, 1, "あ…あの…えっと…\n栗…林…くるみ…です……", "栗林 くるみ", 0, 0, 0, 1021, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "こんな私に貴重な時間を\n割いていただき、", 0, "なんてありがとうございます！", 1.4, 1, "風宮よりです。\nあああああ！", "風宮 より", 0, 0, 0, 1022, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "おにいちゃんどこいくの？\nえ？", 0, "私こっち行きたいー\nね、早く早くー", 1.5, 1, "私、アヤネ！\nぷうきちと一緒についてってあげるね！", "北条 綾音", 0, 0, 0, 1023, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "ふ、不束者ですが\nどうぞ末永く…って、", 0, "これて何か違う…\nあああすみません！", 1.4, 1, "わっ…わっ…私、\n天野すずめといいます！", "天野 すずめ", 0, 0, 0, 1025, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "あなたは…運命の……\n伴侶……", 0, "離しませんわ………\n絶対に…!!", 1.4, 1, "……クスクス…私は\n…倉石恵理子……", "倉石 恵理子", 0, 0, 0, 1027, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 0, "…そうでしょ？？", 1.4, 1, "佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", "佐々木 咲恋", 0, 0, 0, 1028, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "ぇっと…\nキミ、私のこと知らないの?!", 0, "あはは、\n私もまだまだだなぁ～", 1.4, 1, "桜井望だよ！\nよろしくねっ", "桜井 望", 0, 0, 0, 1029, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "初めまして、\n私はニノン・ジュベール申すデス！", 0, "ショーグン、\nワタシと一緒に天下統一デース！", 1.4, 1, "デケデケデンっ！", "ニノン・ジュベール", 0, 0, 0, 1030, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "でもって私の隣にいるのが……\nえ、見えない？", 0, "おかしいですね……", 1.4, 1, "上喜しのぶです。\n手元のドクロが父です。", "上喜 しのぶ", 0, 0, 0, 1031, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "けんども\nそれには足りないモンが…", 0, "そう、\nオラのボケに突っ込める相方が…！", 1.5, 1, "目指すはビッグな\nお笑い芸人だっぺ！", "野戸まひる", 0, 0, 0, 1033, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "ちょっと緊張しちゃって…", 0, "ちょ\nちょっと一杯飲んできます…！", 1.4, 1, "あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", "綾瀬 ゆかり", 0, 0, 0, 1034, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "知らない人とは話しちゃいけないので", 0, "これ以上お話しすることは…\nないです！", 1.5, 1, "氷川鏡華…です", "氷川 鏡華", 0, 0, 0, 1036, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "……あ、アラーム。", 0, "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 1.4, 1, "柏崎…栞です。", "柏崎 栞", 0, 0, 0, 1038, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "私、一人も友達がいなくて……", 0, "野に咲く花が、\n唯一の話相手です。", 1.4, 1, "ふ、双葉碧です。", "双葉 碧", 0, 0, 0, 1040, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 0, "そう思っています。", 1.4, 1, "三角千歌です。", "三角 千歌", 0, 0, 0, 1042, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "あぁ？\nお前のそいつの仲間か？", 0, "う、疑ってすまなかったな…", 1.4, 1, "安芸真琴だ。", "安芸 真琴", 0, 0, 0, 1043, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "生けとし生ける全ての者よ！", 0, "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 1.4, 1, "わらわこそは夜を総べる者！", "イリヤ・オーンスタイン", 0, 0, 0, 1044, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "ぐふふふふ……はっ！", 0, "ｌク、クウカに何かご用ですか!?", 1.4, 1, "そこで騎士は妖精を乱暴に……", "遠見 空花", 0, 0, 0, 1045, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 0, "う～ん…\n猫ってホントに最高にゃ～♪", 1.4, 1, "宮坂たまきにゃ♪\n猫はいいにゃよ？", "宮坂たまき", 0, 0, 0, 1046, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "それでは早速クエストに…", 0, "…と思ったら\nバイトの時間だ！\nまたあとでね！", 1.4, 1, "大神美冬よ！", "大神 美冬", 0, 0, 0, 1048, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "クエストもバトルも\n掃除も洗濯も", 0, "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 1.4, 1, "星野静流だよ！", "星野静流", 0, 0, 0, 1049, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "見ての通りの\nセクシー美少女で", 0, "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 1.5, 1, "アタシは玉泉美咲。", "玉泉美咲", 0, 0, 0, 1050, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "？？？？", 0, "？？？？", 1.4, 1, "？？？", "リマ", 0, 0, 0, 1052, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "菓子でつろうなどと\n稚拙な策を……", 0, "そ、そこまでいうなら\nもらってやる", 1.5, 1, "モニカ・ヴァイスヴィントだ。", "モニカ・ヴァイスヴィント", 0, 0, 0, 1053, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "菓子でつろうなどと\n稚拙な策を……", 0, "そ、そこまでいうなら\nもらってやる", 1.5, 1, "モニカ・ヴァイスヴィントだ。", "ペコリーヌ", 0, 0, 0, 1058, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "菓子でつろうなどと\n稚拙な策を……", 0, "そ、そこまでいうなら\nもらってやる", 1.5, 1, "モニカ・ヴァイスヴィントだ。", "コッコロ", 0, 0, 0, 1059, 0, 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES (1, 2, "菓子でつろうなどと\n稚拙な策を……", 0, "そ、そこまでいうなら\nもらってやる", 1.5, 1, "モニカ・ヴァイスヴィントだ。", "キャル", 0, 0, 0, 1060, 0, 1);
